import { useEffect, useState } from "react";
import axios from "axios";

export default function LiveTextPage() {
  const [live, setLive] = useState(null);
  const [loading, setLoading] = useState(true);
  const [inn, setInn] = useState(1);

  console.log(inn);
  useEffect((inn) => {
    const fetchLive = async (inn) => {
      try {
        // 서버에 요청
        const res = await axios.get(`http://localhost:5001/api/relay`, {
          params: {
            le_id: 1,
            sr_id: 0,
            g_id: "20180721OBLG0",
            inning: inn,
            order: "ASC",
          },
        });;

        setLive(res.data);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchLive();
  }, []);

  if (loading) return <p className="text-center p-4">불러오는 중...</p>;
  if (!live) return <p className="text-center p-4">데이터가 없습니다.</p>;

  const handleChange = (e) => {
    const selected = e.target.value; // YYYY-MM-DD → YYYYMMDD
    setInn(selected);
  };

  return (
    <div className="max-w-2xl mx-auto p-4">
      <h1 className="text-xl font-bold mb-4">KBO 문자중계</h1>
      <input type="size" onChange={handleChange} className="border p-2 rounded mb-4" />

      {live.listInnTb.map((inning, inningIdx) => (
        <div key={inningIdx} className="mb-6">
          <h4 className="text-s font-bold mb-2">
            {inn}회{inning.TB_NM} {inning.T_NM} 공격
          </h4>

          <div className="border rounded-lg p-4 bg-white shadow">
            {inning.listBatOrder.map((bat, batIdx) => (
              <div key={batIdx} className="mb-4">
                <h2 className="text-lg font-semibold">
                  {bat.BAT_ORDER_NO}번타자 {bat.BAT_P_NM}
                  <img src={`https://6ptotvmi5753.edge.naverncp.com/KBO_IMAGE/person/middle/2018/${bat.BAT_P_ID}.jpg`} alt="선수 프로필"/>
                </h2>
                <ul className="mt-2 space-y-2">
                  {bat.listData.map((play, playIdx) => (
                    <li
                      key={playIdx}
                      className="p-2 border-b last:border-none text-sm"
                    >
                      {play.LIVETEXT_IF}
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>

  );
}
